1	type Quote = { premium: number };
2	type Item = { type: string; cursed?: boolean; enchantment?: number };
3	
4	const PROCESSING_FEE = 5;
5	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
6	  sword: 100,
7	  staff: 80,
8	  amulet: 60,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	const ALIKE_BLOCK_SIZE = 3;
14	const ALIKE_BLOCK_PREMIUM = 60;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const LOYALTY_DISCOUNT_RATE = 0.2;
20	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
21	
22	const basePremiumFor = (item: Item): number =>
23	  BASE_PREMIUM_BY_TYPE[item.type];
24	
25	const curseSurchargeRateFor = (item: Item): number =>
26	  item.cursed ? CURSE_SURCHARGE_RATE : 0;
27	
28	const enchantmentSurchargeRateFor = (item: Item): number =>
29	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
30	    ? HIGH_ENCHANTMENT_SURCHARGE_RATE
31	    : 0;
32	
33	const totalSurchargeRateFor = (item: Item): number =>
34	  curseSurchargeRateFor(item) + enchantmentSurchargeRateFor(item);
35	
36	const itemPremiumFor = (item: Item): number =>
37	  basePremiumFor(item) * (1 + totalSurchargeRateFor(item));
38	
39	const sumItemPremiums = (items: Item[]): number =>
40	  items.reduce((sum, item) => sum + itemPremiumFor(item), 0);
41	
42	const isAlikeBlock = (items: Item[]): boolean =>
43	  items.length === ALIKE_BLOCK_SIZE &&
44	  items.every((item) => item.type === items[0].type);
45	
46	const componentsPremium = (items: Item[]): number =>
47	  isAlikeBlock(items) ? ALIKE_BLOCK_PREMIUM : sumItemPremiums(items);
48	
49	const loyaltyDiscountRateFor = (customer?: { yearsWithMHPCO: number }): number =>
50	  (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD
51	    ? LOYALTY_DISCOUNT_RATE
52	    : 0;
53	
54	const firstInsuranceSurchargeRateFor = (firstInsurance?: boolean): number =>
55	  firstInsurance ? FIRST_INSURANCE_SURCHARGE_RATE : 0;
56	
57	type QuoteInput = {
58	  customer?: { yearsWithMHPCO: number };
59	  firstInsurance?: boolean;
60	  items: Item[];
61	};
62	
63	const policyAdjustmentRateFor = (input: QuoteInput): number =>
64	  firstInsuranceSurchargeRateFor(input.firstInsurance) -
65	  loyaltyDiscountRateFor(input.customer);
66	
67	export const quote = (input: QuoteInput): Quote => {
68	  const componentsTotal = componentsPremium(input.items);
69	  const policyTotal = componentsTotal + componentsTotal * policyAdjustmentRateFor(input);
70	  return { premium: policyTotal + PROCESSING_FEE };
71	};
72	
73	export const claim = (_input: unknown): unknown => undefined;
